var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"오늘도 머신갑이나 만지작거리면서 골방에 틀어박혀 있었어? 가끔은 밖에도 좀 돌아다니지 그래?","JPN":"今日もマシーン甲なんかいじりながら引きこもってたの？　たまには外の空気も吸ってくれば？","ENG":"So, you spent another day holed up in your little room, fiddlin' with Machine G.A.P.? You should, like, get out more once in a while.","TWN":"今天也要窩在小房間裡摸機甲嗎？偶爾也該出去走走吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"당신이 밖을 돌아다녀야 위기도 좀 맞닥뜨리고, 누군가의 도움도 필요로 하게 될 거 아냐? 무슨 일이 생기면, 내가 구해줄 테니까.","JPN":"外に出てくれないと危機に陥ることもないし、誰かの助けが必要なことも起こらないじゃない。何かあったら私が助けるからさ。","ENG":"If you actually, like, walk around outside, you're bound to run into trouble sooner or later. And then you'll need someone's help, right? If anythin' happens, I'll save you.","TWN":"你得在外面走動才會遇到危機，也才會需要別人的幫助啊？要是出了什麼事，我會去救你的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그래야 관리자 양반도 바깥을 마음껏 돌아다니면서, 누가 자길 지켜주는지 알고 좀 더 감사하며 살지 않겠어? 일석이조네.","JPN":"そうすれば管理者も自由に出歩きながら、私に守られていることを実感して感謝する毎日を送れるでしょ？　まさに一石二鳥だね。","ENG":"That way, you can roam around all you want and actually realize who's keepin' you safe. Might even learn to live with a little more gratitude. See? Everybody wins.","TWN":"這樣管理者也能放心在外頭活動，知道有人在守護自己，才會更感恩活著。這真是一舉兩得。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"…왜 그렇게 날 돕고 싶어하냐니? 그게 회사 사장의 탈을 쓴 작자가 직원한테 할 말인가?","JPN":"……なぜそんなに人を助けたがるのかって？　それ、会社の社長っていう肩書を持ってる人が社員に言うセリフじゃないから。","ENG":"...Why do I want to help you that much? That really somethin' a company boss says to their own employee?","TWN":"……你問我為什麼這麼想幫你？這是披著公司老闆皮的人該對員工說的話嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"날 거두고 가르쳐 주신 대사님께서 그런 말씀을 자주 하셨거든. 사람 관계는 고마워하는 마음으로 이어진다-, 감사는 하는 쪽도 받는 쪽도 기분이 좋다-","JPN":"私を引き取っていろんなことを教えてくれた大師がよく言ってたの。人間関係は感謝の気持ちで繋がるものだって。感謝はする側もされる側も気持ちが良いものだって。","ENG":"My master used to say this all the time. Like, people are connected through gratitude. Being thankful feels good for the one who gives it, and the one who receives it.","TWN":"收留我、教導我的大師常說人與人之間，是靠感謝的心維繫—感謝，讓給予和接受的人都會感到幸福—"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"관리자 양반은… 나랑 이어져서 기분이 좋아지는 게 싫은 거야?","JPN":"管理者は……私と繋がって気持ちよくなりたくない？","ENG":"So, Mister Administrator... Do you really, like, hate the idea of being connected to me and, like, feelin' good because of it?","TWN":"管理者……不想和我有連結而感到幸福嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"…….","JPN":"…….","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"잠깐, 말하고 나니 좀 어감이 이상하네. 그냥 못 들은 걸로 해.","JPN":"待って、今のはちょっと語弊があった。聞かなかったことにして。","ENG":"Wait. Now that I said it out loud, that sounded, like, kinda weird. Just pretend, like, you didn't hear that.","TWN":"等等，說出口才發現好像有點怪怪的。你就當沒聽到吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"뭐, 뭐야?! 그 반응? 누가 고백이라도 했어? 왜 거절해야 할지 말아야 할지 곤란한 표정인 건데?!","JPN":"な、何なの、その反応！？　告白じゃないからね？　なんで断ったほうがいいかなって悩んでる顔してるわけ！？","ENG":"H-hey, what's that reaction?! I didn't confess anythin'! Why do you look like you're tryin' to decide whether to reject me or not?!","TWN":"什、什麼啊？！你那是什麼反應？！誰說那是告白？ 你那副該不該拒絕的為難表情是怎樣啦？！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"오해야! 난 그런 말 한 적 없다니까! 잊어버려! 누가 누구더러 변태라는 거야! 죽어! 바보!","JPN":"誤解だよ！　私はそんなこと言ってない！　忘れて！　誰が変態だよ、バカ！　出てけ！","ENG":"It's a misunderstanding! I never said anythin' like that! Forget it! Who are you calling a pervert?! Drop dead! Idiot!","TWN":"誤會！我才沒說那種話！快忘掉！說誰是變態啊！去死啦！笨蛋！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};